{{/* templates/_helpers.tpl */}}
{{- define "myapp.image" -}}
{{- $img := .Values.image | default dict -}}
{{- $registry := $img.registry | default "" -}}
{{- $repo := required "image.repository is required" $img.repository -}}
{{- $tag := $img.tag | default .Chart.AppVersion -}}
{{- $digest := $img.digest | default "" -}}
{{- $base := $repo -}}
{{- if $registry -}}
  {{- $base = printf "%s/%s" $registry $repo -}}
{{- end -}}
{{- if $digest -}}
  {{- printf "%s@%s" $base $digest -}}
{{- else -}}
  {{- printf "%s:%s" $base $tag -}}
{{- end -}}
{{- end -}}

{{/* templates/deployment.yaml usage */}}
# containers:
#   - name: {{ .Chart.Name }}
#     image: {{ include "myapp.image" . | quote }}
#
# values.yaml examples:
# image: { repository: payments }                      -> payments:<appVersion>
# image: { registry: ghcr.io/acme, repository: pay, tag: "1.20" } -> ghcr.io/acme/pay:1.20
# image: { repository: pay, digest: sha256:abc... }    -> pay@sha256:abc... (tag ignored)
